  ('real-estate-moex-00838', 'real-estate', 'real-estate-moex-107-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有子女乙丙二人，乙與丁結婚後育有一女戊，丙收養一女己；然乙卻因工時過長，過勞而亡。 甲於乙死亡後兩年亦病逝。有關甲遺產之繼承，下列敘述何者正確？', '["戊、己得以代位繼承", "丙、戊為甲的遺產繼承人", "丙、戊、己為甲的遺產繼承人", "丙、丁、戊、己均為甲的遺產繼承人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "379f995c766a", "answer_pdf_sha1": "233e5e8ad69f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
