  ('real-estate-moex-00840', 'real-estate', 'real-estate-moex-106-ec2e292a', 'sub-real-estate-02', NULL, 'essay', '何謂定型化契約？中央主管機關為促進定型化契約之公平化，依消費者保護法之規
定，擬訂定型化契約應記載或不得記載事項。其內容得包括那些項目？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "0ce5bf5d4f9f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經紀相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00841', 'real-estate', 'real-estate-moex-106-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，經紀人員違反下列何者應予停止執行業務處分？ 收取差價或其他報酬 未自己執行仲介或代銷業務，且未經所屬經紀業同意者 未於不動產出租、出售委託契約書上簽章 在執行業務過程中，未以不動產說明書向與委託人交易之相對人解說', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "0ce5bf5d4f9f", "answer_pdf_sha1": "2b4255695cb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00842', 'real-estate', 'real-estate-moex-106-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列有關不動產經紀人員經紀業之敘述，何者錯誤？ 經紀業因業務需要，必要時得以在其公司工作多年，表現良好，但未具備經紀人資格者，從事仲介或 代銷業務 經營仲介業務者，應揭示報酬標準及收取方式，於營業處所明顯之處 經紀業刊登廣告與銷售內容時，應與事實相符，並註明經紀業名稱 經紀人員在執行業務過程中，應以不動產說明書向與委託人交易之相對人解說', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "0ce5bf5d4f9f", "answer_pdf_sha1": "2b4255695cb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00843', 'real-estate', 'real-estate-moex-106-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，關於不動產經紀人員之資格，下列敘述何者錯誤？ 經不動產經紀人考試及格者，應具備 1 年以上經紀營業員經驗，始得向直轄市或縣市政府請領經紀人 證書 經紀人證書有效期限為4年。期滿時，應檢附4年內完成專業訓練30個小時以上之證明文件辦理換證 曾經營經紀業，經主管機關撤銷或廢止許可，自撤銷或廢止之日起未滿5年者，不得充任經紀人員 經紀人員應專任一經紀業，並不得為自己或他經紀業執行仲介或代銷業務。但經所屬經紀業同意為他 經紀業執行業務者，不在此限', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "0ce5bf5d4f9f", "answer_pdf_sha1": "2b4255695cb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
